INSERT INTO conformity_regulations (key,name,short_name,full_title,jurisdiction,summary,in_force_date,source_url,requirement_count,sort_order) VALUES ('cra','Cyber Resilience Act','CRA','Regulation (EU) 2024/2847 on horizontal cybersecurity requirements for products with digital elements','European Union','Sets mandatory cybersecurity requirements for the design, development, production and vulnerability handling of any product with digital elements placed on the EU market. Introduces essential product requirements (Annex I Part I), vulnerability-handling requirements (Annex I Part II), CE marking, and risk-based conformity routes tied to product classes.','2024-12-10','https://eur-lex.europa.eu/eli/reg/2024/2847/oj',19,1) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,short_name=EXCLUDED.short_name,full_title=EXCLUDED.full_title,jurisdiction=EXCLUDED.jurisdiction,summary=EXCLUDED.summary,in_force_date=EXCLUDED.in_force_date,source_url=EXCLUDED.source_url,requirement_count=EXCLUDED.requirement_count,sort_order=EXCLUDED.sort_order,updated_at=now();
INSERT INTO conformity_regulations (key,name,short_name,full_title,jurisdiction,summary,in_force_date,source_url,requirement_count,sort_order) VALUES ('ai_act','EU Artificial Intelligence Act','AI Act','Regulation (EU) 2024/1689 laying down harmonised rules on artificial intelligence','European Union','Risk-based framework for AI systems. High-risk systems must meet requirements on risk management, data governance, technical documentation, logging, transparency, human oversight, and accuracy/robustness/cybersecurity, backed by a quality management system, conformity assessment, registration, and post-market monitoring.','2024-08-01','https://eur-lex.europa.eu/eli/reg/2024/1689/oj',12,2) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,short_name=EXCLUDED.short_name,full_title=EXCLUDED.full_title,jurisdiction=EXCLUDED.jurisdiction,summary=EXCLUDED.summary,in_force_date=EXCLUDED.in_force_date,source_url=EXCLUDED.source_url,requirement_count=EXCLUDED.requirement_count,sort_order=EXCLUDED.sort_order,updated_at=now();
INSERT INTO conformity_regulations (key,name,short_name,full_title,jurisdiction,summary,in_force_date,source_url,requirement_count,sort_order) VALUES ('machinery','Machinery Regulation','Machinery','Regulation (EU) 2023/1230 on machinery, repealing Directive 2006/42/EC','European Union','Essential health and safety requirements for machinery, now including explicit cybersecurity provisions for safety-related control systems (protection against corruption, reliability of control systems). Requires a technical file, risk assessment, EU Declaration of Conformity, and — for high-risk categories — third-party conformity assessment.','2023-07-19','https://eur-lex.europa.eu/eli/reg/2023/1230/oj',8,3) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,short_name=EXCLUDED.short_name,full_title=EXCLUDED.full_title,jurisdiction=EXCLUDED.jurisdiction,summary=EXCLUDED.summary,in_force_date=EXCLUDED.in_force_date,source_url=EXCLUDED.source_url,requirement_count=EXCLUDED.requirement_count,sort_order=EXCLUDED.sort_order,updated_at=now();
INSERT INTO conformity_regulations (key,name,short_name,full_title,jurisdiction,summary,in_force_date,source_url,requirement_count,sort_order) VALUES ('iec_62443','IEC 62443 Series','IEC 62443','IEC 62443 — Security for industrial automation and control systems (IACS)','International standard','The reference standard series for OT/ICS cybersecurity. 62443-4-1 defines a secure product development lifecycle (eight practices); 62443-4-2 defines technical component requirements across seven foundational requirements. Target Security Levels (SL 1-4) scale controls to the threat. Widely used as evidence for CRA and Machinery cybersecurity obligations.',NULL,'https://www.iec.ch/blog/understanding-iec-62443',27,4) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,short_name=EXCLUDED.short_name,full_title=EXCLUDED.full_title,jurisdiction=EXCLUDED.jurisdiction,summary=EXCLUDED.summary,in_force_date=EXCLUDED.in_force_date,source_url=EXCLUDED.source_url,requirement_count=EXCLUDED.requirement_count,sort_order=EXCLUDED.sort_order,updated_at=now();
INSERT INTO conformity_regulations (key,name,short_name,full_title,jurisdiction,summary,in_force_date,source_url,requirement_count,sort_order) VALUES ('nis2','NIS2 Directive','NIS2','Directive (EU) 2022/2555 on measures for a high common level of cybersecurity across the Union','European Union','EU-wide cybersecurity directive imposing risk-management, governance and incident-reporting obligations on essential and important entities across critical sectors (energy, transport, water, health, digital infrastructure, manufacturing and more). Unlike the product-focused CRA, NIS2 governs the operator: management accountability, a defined set of technical and organisational measures (Art 21), and strict incident notification timelines (Art 23).','2023-01-16','https://eur-lex.europa.eu/eli/dir/2022/2555/oj',12,5) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,short_name=EXCLUDED.short_name,full_title=EXCLUDED.full_title,jurisdiction=EXCLUDED.jurisdiction,summary=EXCLUDED.summary,in_force_date=EXCLUDED.in_force_date,source_url=EXCLUDED.source_url,requirement_count=EXCLUDED.requirement_count,sort_order=EXCLUDED.sort_order,updated_at=now();
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('secure_by_design','Secure by Design & Default','Building appropriate, risk-proportionate security into a product from the outset, including secure default configuration and minimised attack surface.',1) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('risk_management','Risk Management','Establishing and maintaining a process to identify, assess and treat security and safety risks throughout the product lifecycle.',2) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('vulnerability_handling','Vulnerability Handling','Identifying, testing for, remediating and disclosing vulnerabilities, including coordinated disclosure.',3) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('secure_update','Secure Update Management','Providing and securely distributing security updates and patches over the product''s supported lifetime.',4) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('sbom_supply_chain','SBOM & Supply Chain','Identifying and managing components and third-party dependencies, including a software bill of materials.',5) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('access_control','Access Control','Identification, authentication and authorization controls that prevent unauthorised access to the product and its functions.',6) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('data_protection','Data Protection & Integrity','Protecting the confidentiality and integrity of stored, transmitted and processed data, commands and configuration.',7) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('logging_monitoring','Logging & Monitoring','Recording security-relevant activity and enabling detection of, and response to, security events.',8) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('incident_reporting','Incident Reporting','Notifying authorities and users of actively exploited vulnerabilities and severe or serious incidents within mandated timeframes.',9) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('technical_documentation','Technical Documentation','Compiling and maintaining the technical documentation / technical file that demonstrates conformity.',10) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('conformity_declaration','Conformity Declaration','Drawing up the EU Declaration of Conformity and applying the appropriate marking.',11) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('human_oversight','Human Oversight & Transparency','Ensuring systems are transparent to and can be effectively overseen and controlled by humans.',12) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('data_governance','Data Governance','Governing the quality, relevance and representativeness of data used to train, validate and operate systems.',13) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('resilience','Resilience & Availability','Maintaining availability of essential functions and resisting denial-of-service, manipulation and other disruptions.',14) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_themes (key,name,description,sort_order) VALUES ('post_market','Post-market Monitoring','Actively monitoring products in the field and feeding findings back into risk management over the support period.',15) ON CONFLICT (key) DO UPDATE SET name=EXCLUDED.name,description=EXCLUDED.description,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','risk_management','4-1 SM','Security management','Establish a security management process governing the development lifecycle, including roles, responsibilities and a defined scope of the process.','process',ARRAY['supplier']::text[],2,1) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('ai_act','risk_management','Art 9','Risk management system','Establish, implement, document and maintain a risk management system running throughout the entire lifecycle of the high-risk AI system.','process',ARRAY['provider']::text[],3,1) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('nis2','risk_management','Art 20','Governance and management accountability','The management bodies of essential and important entities shall approve the cybersecurity risk-management measures, oversee their implementation, and follow training; they can be held liable for infringements.','governance',ARRAY['operator']::text[],2,1) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('machinery','secure_by_design','Annex III 1.1.9','Protection against corruption','Machinery shall be designed and constructed so that connection to it of another device does not lead to a hazardous situation, and that hardware/software transmitting safety signals are protected against corruption.','product_requirement',ARRAY['manufacturer']::text[],1,1) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('cra','secure_by_design','Annex I(1)','Appropriate level of cybersecurity based on risk','Products with digital elements shall be designed, developed and produced to ensure an appropriate level of cybersecurity based on the risks.','product_requirement',ARRAY['manufacturer']::text[],5,1) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('ai_act','data_governance','Art 10','Data and data governance','Training, validation and testing data sets shall be subject to data governance and management practices appropriate to the intended purpose.','process',ARRAY['provider']::text[],0,2) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','sbom_supply_chain','4-1 SM-9','Third-party component management','Identify, assess and manage security risks of third-party and open-source components used in the product, maintaining a record of components.','process',ARRAY['supplier']::text[],1,2) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('machinery','resilience','Annex III 1.2.1','Safety and reliability of control systems','Control systems shall be designed and constructed to prevent hazardous situations, withstanding intended operating stresses and external influences, including malicious attempts from third parties to create a hazardous situation.','product_requirement',ARRAY['manufacturer']::text[],1,2) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('cra','vulnerability_handling','Annex I(2)(a)','No known exploitable vulnerabilities on release','Products shall be made available on the market without known exploitable vulnerabilities.','product_requirement',ARRAY['manufacturer']::text[],1,2) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('nis2','risk_management','Art 21(2)(a)','Risk analysis and information system security policies','Entities shall adopt policies on risk analysis and information system security as the foundation of an all-hazards, risk-based approach to protecting network and information systems.','process',ARRAY['operator']::text[],2,2) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('ai_act','technical_documentation','Art 11','Technical documentation (Annex IV)','Draw up technical documentation before the system is placed on the market and keep it up to date, demonstrating conformity as set out in Annex IV.','documentation',ARRAY['provider']::text[],1,3) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('nis2','incident_reporting','Art 21(2)(b)','Incident handling','Entities shall implement incident-handling measures covering prevention, detection, analysis, containment, response and recovery.','process',ARRAY['operator']::text[],0,3) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','secure_by_design','4-1 SR','Specification of security requirements','Document and maintain security requirements for the product, derived from its intended environment and threat model.','process',ARRAY['supplier']::text[],1,3) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('cra','secure_by_design','Annex I(2)(b)','Secure by default configuration','Products shall be made available with a secure by default configuration, including the possibility to reset the product to its original state.','product_requirement',ARRAY['manufacturer']::text[],1,3) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('machinery','access_control','Annex III 1.2.1(a)','Protection of safety-related control software','Safety-related control software and access to it shall be protected against unintended or intentional corruption and unauthorised modification.','product_requirement',ARRAY['manufacturer']::text[],1,3) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','secure_by_design','4-1 SD','Secure by design','Apply secure design principles, including defence in depth and threat modelling, throughout product design.','process',ARRAY['supplier']::text[],2,4) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('cra','secure_update','Annex I(2)(c)','Security updates','Ensure vulnerabilities can be addressed through security updates, including, where applicable, automatic updates and user notification.','product_requirement',ARRAY['manufacturer']::text[],2,4) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('ai_act','logging_monitoring','Art 12','Record-keeping and logging','High-risk AI systems shall technically allow for the automatic recording of events (logs) over the lifetime of the system.','product_requirement',ARRAY['provider']::text[],1,4) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
