INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('cra','technical_documentation','Annex VII','Technical documentation','Draw up technical documentation containing all relevant data and details of the means used to ensure conformity, kept for at least ten years.','documentation',ARRAY['manufacturer']::text[],3,16) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','access_control','3-3 SR 1.2','Software process and device identification','The control system shall identify and authenticate all software processes and devices before allowing them to access the system.','product_requirement',ARRAY['integrator']::text[],0,16) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','access_control','3-3 SR 2.1','Authorization enforcement','The control system shall enforce authorizations assigned to all users and processes, restricting access to the minimum necessary for the assigned role (least privilege).','product_requirement',ARRAY['integrator']::text[],2,17) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('cra','incident_reporting','Art 14','Report exploited vulnerabilities and severe incidents','Notify an actively exploited vulnerability or a severe incident: an early warning within 24 hours and a notification within 72 hours to the CSIRT and ENISA.','reporting',ARRAY['manufacturer']::text[],2,17) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('cra','conformity_declaration','Annex V','EU Declaration of Conformity','Draw up an EU declaration of conformity stating that the essential requirements have been fulfilled, and affix the CE marking.','documentation',ARRAY['manufacturer']::text[],2,18) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','access_control','3-3 SR 2.5','Session lock and termination','The control system shall lock or terminate a session after a configurable period of inactivity or on demand, preventing further access until re-authentication.','product_requirement',ARRAY['integrator']::text[],0,18) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('cra','post_market','Art 13(8)','Support period and updates over lifetime','Ensure that vulnerabilities are handled effectively during a defined support period reflecting the expected product lifetime.','process',ARRAY['manufacturer']::text[],1,19) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','data_protection','3-3 SR 3.1','Communication integrity','The control system shall protect the integrity of transmitted information, detecting unauthorised changes to communications during transmission.','product_requirement',ARRAY['integrator']::text[],1,19) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','data_protection','3-3 SR 3.2','Malicious code protection','The control system shall provide protection against, and detection of, malicious code at entry and exit points and on affected devices.','product_requirement',ARRAY['integrator']::text[],0,20) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','data_protection','3-3 SR 4.1','Information confidentiality','The control system shall protect the confidentiality of information at rest and in transit for which explicit read authorization is required, using cryptographic mechanisms where appropriate.','product_requirement',ARRAY['integrator']::text[],3,21) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','secure_by_design','3-3 SR 5.1','Network segmentation','The control system shall logically segment control networks from non-control networks and partition the system into zones and conduits according to the risk assessment.','product_requirement',ARRAY['integrator']::text[],1,22) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','secure_by_design','3-3 SR 5.2','Zone boundary protection','The control system shall monitor and control communications at zone boundaries to enforce the defined conduits, denying network traffic by default and allowing it by exception.','product_requirement',ARRAY['integrator']::text[],0,23) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','logging_monitoring','3-3 SR 6.1','Audit log accessibility','The control system shall provide the capability to access audit logs on a read-only basis to authorised personnel and tools.','product_requirement',ARRAY['integrator']::text[],2,24) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','logging_monitoring','3-3 SR 6.2','Continuous monitoring','The control system shall provide the capability to continuously monitor security-relevant events using commonly accepted tools and mechanisms.','product_requirement',ARRAY['integrator']::text[],0,25) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','resilience','3-3 SR 7.1','Denial-of-service protection','The control system shall maintain essential functions when operating in a degraded mode as the result of a denial-of-service event.','product_requirement',ARRAY['integrator']::text[],2,26) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
INSERT INTO conformity_requirements (regulation_key,theme_key,ref_code,title,description,obligation_type,applies_to,mapping_count,sort_order) VALUES ('iec_62443','resilience','3-3 SR 7.2','Resource management and recovery','The control system shall limit the use of resources by security functions to prevent resource exhaustion, and support backup and recovery to a known secure state after a disruption.','product_requirement',ARRAY['integrator']::text[],0,27) ON CONFLICT (regulation_key,ref_code) DO UPDATE SET theme_key=EXCLUDED.theme_key,title=EXCLUDED.title,description=EXCLUDED.description,obligation_type=EXCLUDED.obligation_type,applies_to=EXCLUDED.applies_to,mapping_count=EXCLUDED.mapping_count,sort_order=EXCLUDED.sort_order;
